mapper.select:
select p.id, p.cover_url as coverUrl, p.title, p.content, u.username, p.like_count as likeCount, p.comment_count as commentCount, case when pl.id is null then false else true end as liked, p.status, p.create_time as createTime from post p left join user u on p.user_id = u.id left join post_like pl on pl.post_id = p.id and pl.user_id = #{currentUserId}
p.is_deleted = 0
and p.title like concat('%', #{title}, '%')
and u.username like concat('%', #{username}, '%')
and p.status = #{status}
order by p.create_time desc

mapper.update:
update post
set like_count = #{likeCount}
where id = #{id}
  and is_deleted = 0

update post
set comment_count = #{commentCount}
where id = #{id}
  and is_deleted = 0

update post
set status = #{status},
    reject_reason = #{rejectReason}
where id = #{id}
  and is_deleted = 0

update post
set is_deleted = 1
where id = #{id}
  and user_id = #{userId}
  and is_deleted = 0
